// Assuming 'input' is the raw response you received
let rawData = $input.first().json

function unwrapResponse(data) {
  let result = data;

  // 1. Handle if it's an array: [{...}]
  if (Array.isArray(result) && result.length > 0) {
    result = result[0];
  }

  // 2. Handle if it's nested in an 'output' key: { output: ... }
  if (result && typeof result === 'object' && result.output) {
    result = result.output;
  }

  // 3. Handle if the result is a JSON string (common in 'output' keys)
  return result;
}

const cleanIntent = unwrapResponse(rawData);
return {response_message:cleanIntent};
